#!/usr/bin/env node
import{execFileSync}from"node:child_process";import{mkdtempSync,rmSync,writeFileSync}from"node:fs";import{tmpdir}from"node:os";import{join}from"node:path";
const root=process.env.AEON_MEMORY_TS_BASELINE;if(!root)throw new Error("AEON_MEMORY_TS_BASELINE required");const sha=execFileSync("git",["-C",root,"rev-parse","HEAD"],{encoding:"utf8"}).trim();if(sha!=="4339e63650920871eb0e8888083a1779d114e3ae")throw new Error(`wrong baseline ${sha}`);if(!process.env.AEON_MEMORY_RECALL_ORACLE_CHILD){execFileSync("npx",["tsx",new URL(import.meta.url).pathname],{cwd:root,stdio:"inherit",env:{...process.env,AEON_MEMORY_RECALL_ORACLE_CHILD:"1"}});process.exit(0)}
const {performAutoRecall}=await import(join(root,"src/core/hooks/auto-recall.ts"));const dir=mkdtempSync(join(tmpdir(),"aeon-memory-recall-oracle-"));
const rows=[{record_id:"high",content:"A".repeat(90),type:"persona",priority:90,scene_name:"prefs",score:.95,timestamp_str:"",session_key:"s",session_id:"i",metadata_json:"{}"},{record_id:"low",content:"second memory",type:"episodic",priority:10,scene_name:"work",score:.8,timestamp_str:"",session_key:"s",session_id:"i",metadata_json:"{}"}];
const calls=[];const store={isFtsAvailable:()=>true,getCapabilities:()=>({nativeHybridSearch:false}),searchL1Fts:async(q,l)=>{calls.push([q,l]);return rows},searchL1Vector:async()=>[]};const cfg={recall:{strategy:"keyword",maxResults:2,scoreThreshold:.3,maxCharsPerMemory:60,maxTotalRecallChars:101,timeoutMs:1000}};
const populated=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg,pluginDataDir:dir,vectorStore:store});
const vectorRows=[{...rows[1],record_id:"vec",content:"vector memory",score:.99},{...rows[0],record_id:"high",score:.7}];const embeddingCalls=[];const vectorStore={...store,searchL1Vector:async(v,l)=>{calls.push(["vector",v,l]);return vectorRows}};const embedding={embed:async(q,o)=>{embeddingCalls.push([q,o]);return[1,0]}};
const hybrid=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg:{recall:{...cfg.recall,strategy:"hybrid",scoreThreshold:.01,maxCharsPerMemory:0,maxTotalRecallChars:0},embedding:{recallTimeoutMs:222}},pluginDataDir:dir,vectorStore,embeddingService:embedding});
const hybridFallback=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg:{recall:{...cfg.recall,strategy:"hybrid",scoreThreshold:.01,maxCharsPerMemory:0,maxTotalRecallChars:0}},pluginDataDir:dir,vectorStore});
const vector=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg:{recall:{...cfg.recall,strategy:"embedding",maxCharsPerMemory:0,maxTotalRecallChars:0},embedding:{recallTimeoutMs:222}},pluginDataDir:dir,vectorStore,embeddingService:embedding});
const slow={...store,searchL1Fts:async()=>{await new Promise(r=>setTimeout(r,40));return rows}};const timeout=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg:{recall:{...cfg.recall,timeoutMs:5}},pluginDataDir:dir,vectorStore:slow});
writeFileSync(join(dir,"persona.md"),"# Stable persona\n");const astralGate=await performAutoRecall({userText:"😀",actorId:"a",sessionKey:"s",cfg,pluginDataDir:dir,vectorStore:store});
const astralRows=[{...rows[0],record_id:"emoji",content:"😀".repeat(20),scene_name:""},{...rows[1],record_id:"tail",content:"tail",scene_name:""}];const astralStore={...store,searchL1Fts:async()=>astralRows};
const astralBudget=await performAutoRecall({userText:"😀a",actorId:"a",sessionKey:"s",cfg:{recall:{...cfg.recall,maxCharsPerMemory:0,maxTotalRecallChars:45}},pluginDataDir:dir,vectorStore:astralStore});
const failingStore={...store,searchL1Fts:async()=>{throw new Error("fts unavailable")}};
const searchFailure=await performAutoRecall({userText:"memory query",actorId:"a",sessionKey:"s",cfg,pluginDataDir:dir,vectorStore:failingStore});
writeFileSync(join(new URL(".",import.meta.url).pathname,"recall_runtime_oracle.json"),JSON.stringify({populated,hybrid,hybridFallback,vector,timeout:timeout??null,astralGate,astralBudget,searchFailure,calls,embeddingCalls},null,2)+"\n");rmSync(dir,{recursive:true,force:true});
